import React from "react";
import styled from "styled-components";
import randomColor from "randomcolor";

import ContentParent from "./content_parent";
import IntroPanel from "./intro";
import WorkPanel from "./work";
import ProjectsPanel from "./projects";
import AboutPanel from "./about";
import Footer from "./footer";

import ColorButton from "./color_button";
import ResumeButton from "./resume_button";

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      colors: {
        main: "#ffffff",
        panel: "#b5feff",
        button: "#ffffff",
        heading: "#2f7fc4",
        text: "#1c1c1c",
        text_highlight: "#ffb429",
      },
    };
  }

  randomizeColors = (e) => {
    e.preventDefault();

    let randomColors = randomColor({
      count: 10,
      luminosity: "random",
      hue: "random",
    });

    let newColors = {
      main: randomColors[0],
      panel: randomColors[1],
      button: randomColors[2],
      heading: randomColors[3],
      text: randomColors[4],
      text_highlight: randomColors[5],
    };

    this.setState({ colors: newColors });
  };
  // console.log(colors);
  // console.log(this.state.colors);
  // console.log("randomizing the color scheme!");

  render() {
    return (
      <ContentParent colors={this.state.colors}>
        <ColorButton clickHandler={this.randomizeColors} />
        <IntroPanel />
        <AboutPanel />
        <WorkPanel />
        <ProjectsPanel />
        <Footer />
      </ContentParent>
    );
  }
}

export default App;

const MainContainer = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  height: 100%;
  width: 100%;
  background: ${(props) => props.color};
  transition: all 0.8s ease-in;
  * {
    transition: all 0.8s ease-in;
  }
`;
